from dataclasses import dataclass, field
from typing import Callable, Any
from collections import deque

@dataclass
class State:
    data: dict
    def __hash__(self): return hash(frozenset(self.data.items()))
    def __eq__(self, other): return self.data == other.data

@dataclass
class Action:
    name: str
    precondition: Callable[[State], bool]
    effect: Callable[[State], State]  # returns new state

def bfs_plan(start: State, goal_test: Callable[[State], bool],
             actions: list[Action]) -> list[str] | None:
    """Breadth-first search: finds shortest action sequence to goal."""
    queue = deque([(start, [])])  # (state, path so far)
    visited = {start}
    while queue:
        state, path = queue.popleft()
        if goal_test(state):
            return path
        for action in actions:
            if action.precondition(state):
                next_state = action.effect(state)
                if next_state not in visited:
                    visited.add(next_state)
                    queue.append((next_state, path + [action.name]))
    return None  # no path found

class GoalBasedAgent:
    def __init__(self, actions: list[Action], goal_test: Callable[[State], bool]):
        self.actions = actions
        self.goal_test = goal_test
        self._plan: list[str] = []

    def act(self, current_state: State) -> str | None:
        if not self._plan:
            if self.goal_test(current_state):
                return None  # already at goal
            self._plan = bfs_plan(current_state, self.goal_test, self.actions) or []
        if not self._plan:
            return None  # no path to goal
        return self._plan.pop(0)

# A* search for goal-based agent with a cost heuristic
# h(s) = Manhattan distance to goal (admissible heuristic)
import heapq
from dataclasses import dataclass
from typing import Callable

@dataclass(frozen=True)
class GridPos:
    x: int
    y: int

def manhattan(a: GridPos, b: GridPos) -> int:
    return abs(a.x - b.x) + abs(a.y - b.y)

def astar(start: GridPos, goal: GridPos, blocked: set[GridPos]) -> list[str] | None:
    # Priority queue: (f, g, state, path)
    h = manhattan(start, goal)
    heap = [(h, 0, start, [])]
    visited: dict[GridPos, int] = {}  # state -> best g seen
    MOVES = [("right", 1, 0), ("left", -1, 0), ("down", 0, 1), ("up", 0, -1)]
    while heap:
        f, g, pos, path = heapq.heappop(heap)
        if pos == goal:
            return path
        if visited.get(pos, float("inf")) <= g:
            continue
        visited[pos] = g
        for name, dx, dy in MOVES:
            npos = GridPos(pos.x + dx, pos.y + dy)
            if npos not in blocked:
                ng = g + 1
                nf = ng + manhattan(npos, goal)
                heapq.heappush(heap, (nf, ng, npos, path + [name]))
    return None

blocked = {GridPos(1, 1), GridPos(2, 1)}
plan = astar(GridPos(0, 0), GridPos(3, 3), blocked)
print(plan)  # optimal path avoiding obstacles
