# Re-planning when the world changes unexpectedly
from dataclasses import dataclass, field
from typing import Callable
from collections import deque

@dataclass(frozen=True)
class State:
    data: tuple  # use tuple for hashability

@dataclass
class Action:
    name: str
    precondition: Callable
    effect: Callable

def bfs_plan(start, goal_test, actions):
    queue = deque([(start, [])])
    visited = {start}
    while queue:
        state, path = queue.popleft()
        if goal_test(state):
            return path
        for a in actions:
            if a.precondition(state):
                ns = a.effect(state)
                if ns not in visited:
                    visited.add(ns)
                    queue.append((ns, path + [a.name]))
    return None

class AdaptiveGoalAgent:
    def __init__(self, actions: list[Action], goal_test: Callable):
        self.actions = actions
        self.goal_test = goal_test
        self._plan: list[str] = []
        self._expected_state = None

    def act(self, current_state) -> str | None:
        if self.goal_test(current_state):
            return None
        # Re-plan if world changed unexpectedly
        if self._expected_state and current_state != self._expected_state:
            print("Unexpected state — re-planning")
            self._plan = []
        if not self._plan:
            self._plan = bfs_plan(current_state, self.goal_test, self.actions) or []
        if not self._plan:
            return None
        action_name = self._plan.pop(0)
        action = next(a for a in self.actions if a.name == action_name)
        self._expected_state = action.effect(current_state)
        return action_name

# Hierarchical goal decomposition
# Break a complex goal into subgoals, each solved independently
from dataclasses import dataclass, field
from collections import deque
from typing import Callable

@dataclass
class Action:
    name: str
    precondition: Callable
    effect: Callable

def bfs_plan(start, goal_test, actions):
    queue = deque([(start, [])])
    visited = {start}
    while queue:
        state, path = queue.popleft()
        if goal_test(state):
            return path
        for a in actions:
            if a.precondition(state):
                ns = a.effect(state)
                if ns not in visited:
                    visited.add(ns)
                    queue.append((ns, path + [a.name]))
    return None

@dataclass
class Subgoal:
    name: str
    goal_test: Callable

class HierarchicalGoalAgent:
    """Solves each subgoal in order, chaining the plans."""
    def __init__(self, actions: list[Action]):
        self.actions = actions

    def plan(self, start, subgoals: list[Subgoal]) -> list[str]:
        full_plan = []
        state = start
        for subgoal in subgoals:
            if subgoal.goal_test(state):
                continue  # already satisfied
            segment = bfs_plan(state, subgoal.goal_test, self.actions)
            if segment is None:
                raise ValueError(f"Cannot reach subgoal: {subgoal.name}")
            for action_name in segment:
                action = next(a for a in self.actions if a.name == action_name)
                state = action.effect(state)
            full_plan.extend(segment)
        return full_plan

# Application: robot fetch-and-return task
# Subgoal 1: reach the item
# Subgoal 2: pick up the item
# Subgoal 3: return to base
# Each is a simple BFS problem; together they solve the composite task.

# Common pitfall 1: state space explosion
# BFS/DFS visit every reachable state. For large state spaces,
# planning becomes intractable without pruning or a better heuristic.

def bfs_with_limit(start, goal_test, actions, max_depth: int = 50):
    from collections import deque
    queue = deque([(start, [], 0)])
    visited = {start}
    while queue:
        state, path, depth = queue.popleft()
        if goal_test(state):
            return path
        if depth >= max_depth:
            continue  # do not expand beyond limit
        for a in actions:
            if a.precondition(state):
                ns = a.effect(state)
                if ns not in visited:
                    visited.add(ns)
                    queue.append((ns, path + [a.name], depth + 1))
    return None  # no plan within depth limit

# Common pitfall 2: incorrect transition model
# If f(state, action) does not accurately model the real world,
# the agent executes a plan that made sense on paper but fails in reality.
# Fix: validate transition model against a simulation before deployment.

# Common pitfall 3: unsatisfiable goal
# BFS returns None if no path to goal exists.
# Always handle the None case — do not assume a plan will be found.
def safe_act(agent, state):
    action = agent.act(state)
    if action is None:
        # Goal reached or no plan found — ask for new goal or halt
        return "halt"
    return action
